// src/pages/HomePage.jsx

import Header from '../components/layout/Header/Header';
import Footer from '../components/layout/Footer/Footer';
import ServiceList from '../components/services/ServiceList';
import { servicesData } from '../data/servicesData';

const HomePage = () => {
  return (
    <>
      <Header />
      <main>
        {/* Você pode adicionar outras seções aqui, como um Hero, Depoimentos, etc. */}
        
        <section className="services-section">
          <div className="section-container">
            <h2 className="section-title">Nossos Serviços</h2>
            <p className="section-subtitle">Soluções completas para a performance do seu computador.</p>
            
            {/* Aqui é a mágica! Usamos nosso componente de lista e passamos os dados para ele. */}
            <ServiceList services={servicesData} />
          </div>
        </section>

        {/* Aqui entraria o componente do formulário de contato, por exemplo */}

      </main>
      <Footer />
    </>
  );
};

export default HomePage;
